CREATE TABLE "news"."news_cdtn_references" ("news_id" uuid NOT NULL, "cdtn_id" text NOT NULL, PRIMARY KEY ("news_id","cdtn_id") , FOREIGN KEY ("news_id") REFERENCES "news"."news"("id") ON UPDATE cascade ON DELETE cascade, FOREIGN KEY ("cdtn_id") REFERENCES "public"."documents"("cdtn_id") ON UPDATE cascade ON DELETE cascade);COMMENT ON TABLE "news"."news_cdtn_references" IS E'Références sur les contenus du CDTN';
